          { top: "68%", left: "80%", size: 3, delay: "0.3s", dur: "3.6s" },
          { top: "42%", left: "88%", size: 2, delay: "1.8s", dur: "4.4s" },
          { top: "88%", left: "54%", size: 2, delay: "0.6s", dur: "3s" },
        ].map((dot, i) => (
          <div
            key={`dot-${i}`}
            className="absolute pointer-events-none rounded-full"
            style={{
              top: dot.top,
