              background: "oklch(0.62 0.22 41.1 / 0.7)",
              boxShadow: `0 0 ${dot.size * 4}px ${dot.size + 1}px oklch(0.62 0.22 41.1 / 0.22)`,
              animation: `pulse ${dot.dur} ease-in-out infinite`,
              animationDelay: dot.delay,
            }}
          />
