  const [commitMessage, setCommitMessage] = useState("")
  const [gitStatus, setGitStatus] = useState<"idle" | "committing" | "success">("idle")
  const [hasChanges, setHasChanges] = useState(true)

  const handleFileClick = (fileName: string) => {
    setActiveFile(fileName)
    const href = fileName === defaultFile ? `/${locale}` : `/${locale}/${fileName}`
    router.push(href)
  }

  const tabs = [
    { id: "explorer", icon: Files, label: "Explorer (Ctrl+Shift+E)" },
    { id: "search", icon: SearchIcon, label: "Search (Ctrl+Shift+F)" },
    { id: "git", icon: GitBranch, label: "Source Control (Ctrl+Shift+G)", badge: hasChanges ? "1" : null },
    { id: "extensions", icon: Blocks, label: "Extensions (Ctrl+Shift+X)" }
  ]

  const handleTabClick = (tabId: string) => {
    if (activeSidebarTab === tabId && isSidebarOpen) {
      setIsSidebarOpen(false)
    } else {
      setActiveSidebarTab(tabId)
      setIsSidebarOpen(true)
    }
  }

  useEffect(() => {
    if (!searchQuery.trim()) {
      setSearchResults([])
      return
    }

    const query = searchQuery.toLowerCase()
    const results: typeof searchResults = []

    const aboutData = locale === "pt" ? aboutPt : aboutEn
    const aboutStr = JSON.stringify(aboutData, null, 2)
    const aboutLines = aboutStr.split("\n")
    aboutLines.forEach((line, index) => {
      if (line.toLowerCase().includes(query)) {
        results.push({
          file: "igor.json",
          line: index + 1,
          content: line.trim()
        })
      }
    })

    const settingsStr = JSON.stringify(settingsData, null, 2)
    const settingsLines = settingsStr.split("\n")
    settingsLines.forEach((line, index) => {
      if (line.toLowerCase().includes(query)) {
        results.push({
          file: "settings.json",
          line: index + 1,
          content: line.trim()
        })
      }
    })

    const portfolioMockLines = [
      "import { Hero, Journey, Projects, Stack, Contact } from '@/components/sections'",
      "export default function Portfolio() {",
      "  const name = 'Igor Braz'",
      "  const role = 'Full Stack Developer'",
      "  return (",
      "    <div className='portfolio'>",
      "      <Hero name={name} role={role} />",
      "      <Journey />",
      "      <Projects />",
      "      <Stack />",
      "      <Contact />",
      "    </div>",
      "  )",
      "}"
    ]
    portfolioMockLines.forEach((line, index) => {
      if (line.toLowerCase().includes(query)) {
        results.push({
          file: "portfolio.tsx",
          line: index + 1,
          content: line.trim()
        })
      }
    })

  }, [searchQuery, locale])

  const handleCommit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!commitMessage.trim()) return

    setGitStatus("committing")
    setTimeout(() => {
      setGitStatus("success")
      setHasChanges(false)
      setCommitMessage("")
      setTimeout(() => {
        setGitStatus("idle")
      }, 2000)
    }, 1500)
  }

  const getFileIcon = (fileName: string) => {
    const ext = fileName.split(".").pop() || ""
    switch (ext) {
      case "tsx":
      case "jsx":
        return <FileCode2 className="w-4 h-4 shrink-0 text-cyan-400" />
      case "ts":
      case "js":
        return <FileCode className="w-4 h-4 shrink-0 text-blue-400" />
      case "json":
        return <FileJson className="w-4 h-4 shrink-0 text-yellow-500" />
      case "css":
        return <FileText className="w-4 h-4 shrink-0 text-teal-400" />
      case "md":
        return <FileText className="w-4 h-4 shrink-0 text-amber-500" />
      case "svg":
        return <FileCode2 className="w-4 h-4 shrink-0 text-orange-400" />
      default:
        return <FileText className="w-4 h-4 shrink-0 opacity-70" />
    }
  }

  const renderNode = (node: FileNode, depth = 0, currentPath = "") => {
    const isFolder = node.type === "folder"
    const nodePath = currentPath ? `${currentPath}/${node.name}` : node.name
    const isOpen = openFolders[nodePath] || false
    const fileId = node.id || nodePath
    const isActive = activeFile === fileId

    if (isFolder) {
      return (
        <div key={nodePath} className="flex flex-col">
          <div
            onClick={() => toggleFolder(nodePath)}
            className="flex items-center gap-1.5 py-1 pr-2 cursor-pointer transition-colors duration-150 select-none text-[13px] font-sans group"
            style={{
              paddingLeft: `${(depth + 1) * 8}px`,
              color: theme.colors["sideBar.foreground"]
            }}
            onMouseEnter={(e) => {
