            )}
          </AnimatePresence>
        </div>
      )
    }

    return (
      <div
        key={nodePath}
        onClick={() => handleFileClick(fileId)}
        className="flex items-center gap-1.5 py-1 pr-2 cursor-pointer transition-all duration-150 select-none text-[13px] font-sans group relative"
        style={{
