                          }`}
                      >
                        {page}
                      </button>
                    );
                  } else if (
                    page === currentPage - 2 ||
                    page === currentPage + 2
                  ) {
                    return (
                      <span
                        key={page}
                        className="text-muted-foreground px-1 font-mono text-sm"
                      >
                        …
                      </span>
                    );
                  }
                  return null;
                },
              )}
            </div>

            <button
              onClick={() => {
                sendGAEvent("event", "code_dashboard_next_page_click", {
                  label: "Next Page",
